#include<bits/stdc++.h>
using namespace std;
int main(){
    char a[101],b[101];
    cin>>a>>b;
    if(strstr(b,a)!=NULL){
        cout<<a<<" is substring of "<<b;

    }else if(strstr(a,b)!=NULL){
        cout<<b<<" is substring of "<<a;
    }else{
        cout<<"No substring";
    }
}
